// This function adds cards the page to display the data in the array
function showCards() {
  showCards(titles);
}

function showCards(bookData) {
  const cardContainer = document.getElementById("card-container"); //access card container
  cardContainer.innerHTML = ""; //clear in case there is something in the card
  const templateCard = document.querySelector(".card"); // access card template

  for (let i = 0; i < bookData.length; i++) {
    const nextCard = templateCard.cloneNode(true); // Copy the template card onto a new card
    editCardContent(nextCard, bookData[i]); // Apply data to the new card
    cardContainer.appendChild(nextCard); // Add new card to the container
  }
}

function editCardContent(card, data) {
  card.style.display = "block"; // card was initially set to none, but block makes it visible

  const cardHeader = card.querySelector("h2"); // find the header tag in the element
  cardHeader.textContent = data.title; // setting header to given values

  const cardImage = card.querySelector("img");
  cardImage.src = data.image; // setting the source attribute to the given data
  cardImage.alt = data.title + " Poster"; // message for screen readers

  const publishedTag = card.querySelector(".published");
  publishedTag.innerHTML = data.published;

  const authorTag = card.querySelector(".author");
  authorTag.innerHTML = data.author;

  const genreTag = card.querySelector(".genre");
  genreTag.innerHTML = data.genre;

  // You can use console.log to help you debug!
  // View the output by right clicking on your website,
  // select "Inspect", then click on the "Console" tab
  console.log("new card:", data.title, "- html: ", card);
}

// This calls the addCards() function when the page is first loaded
document.addEventListener("DOMContentLoaded", () => {
  showCards(titles);
});

const sortOptions = document.getElementById("sort-container"); // sort-container holds the radio buttons
sortOptions.addEventListener("change", sortCards); // execute when one of the radio buttons has been clicked

const searchInput = document.querySelector("#search");

searchInput.addEventListener("input", (event) => {
  // lambda is c++ is a call back in JS
  let text = event.target.value.toLowerCase();
  let newTitles = titles.filter((obj) => {
    return (
      obj.title.toLowerCase().includes(text) ||
      obj.author.toLowerCase().includes(text) ||
      obj.published.toLowerCase().includes(text) ||
      obj.genre.toLowerCase().includes(text)
    );
  });
  showCards(newTitles);
}); //

function sortCards() {
  //find the buttons
  const titleSort = document.getElementById("title");
  const authorSort = document.getElementById("author");
  const yearSort = document.getElementById("year");

  if (titleSort.checked) {
    titles.sort((a, b) => a.title.localeCompare(b.title));
  } else if (authorSort.checked) {
    titles.sort((a, b) => a.author.localeCompare(b.author));
  } else if (yearSort.checked) {
    titles.sort((a, b) => a.published - b.published);
  }
  showCards(titles); // redraw the cards on screen
}

